def count_valid_passwords(n, classes, max_consec):
    MOD = 10**9 + 7
    num_classes = len(classes)
    sizes = [c[0] for c in classes]
    reqs = [c[1] for c in classes]
    if sum(reqs) > n:
        return 0
    import sys
    sys.setrecursionlimit(200000)
    from functools import lru_cache
    NONE_CLS = num_classes
    @lru_cache(maxsize=None)
    def dp(pos, last_cls, run, counts):
        if pos == n:
            for i in range(num_classes):
                if counts[i] < reqs[i]:
                    return 0
            return 1
        result = 0
        for c in range(num_classes):
            new_counts = list(counts)
            new_counts[c] = min(new_counts[c] + 1, reqs[c])
            nc = tuple(new_counts)
            if c != last_cls:
                result = (result + sizes[c] * dp(pos + 1, c, 1, nc)) % MOD
            else:
                if run + 1 <= max_consec:
                    result = (result + dp(pos + 1, c, run + 1, nc)) % MOD
                if sizes[c] > 1:
                    result = (result + (sizes[c] - 1) * dp(pos + 1, c, 1, nc)) % MOD
        return result
    initial_counts = tuple(0 for _ in range(num_classes))
    ans = dp(0, NONE_CLS, 0, initial_counts)
    dp.cache_clear()
    return ans
